import { useState } from 'react';
import axios from 'axios';

const Chat = ({ docId }) => {
  const [question, setQuestion] = useState('');
  const [answer, setAnswer] = useState('');

  const handleChat = async () => {
    const token = localStorage.getItem('token');
    const res = await axios.post(`http://localhost:5000/api/documents/${docId}/chat`, { question }, { headers: { Authorization: `Bearer ${token}` } });
    setAnswer(res.data.answer);
  };

  return (
    <div className="mt-4">
      <input type="text" placeholder="Ask a question" value={question} onChange={(e) => setQuestion(e.target.value)} className="w-full p-2 mb-2 border" />
      <button onClick={handleChat} className="bg-purple-600 text-white p-2">Ask</button>
      {answer && <p className="mt-2">{answer}</p>}
    </div>
  );
};

export default Chat;
